mapper.select:
SELECT CAST(S.sermon_id AS VARCHAR) AS rqstNo , S.title AS title , S.content_html AS cont , S.author_id AS rqstId , S.preacher_name AS preacherName , S.scripture_reference AS scriptureReference , S.sermon_date AS sermonDate , S.worship_type AS worshipType , S.created_at AS insDt , S.updated_at AS uptDt , S.view_count AS views , COALESCE(S.depth, 0) AS depth , CAST(S.group_no AS VARCHAR) AS groupNo , CAST(S.parent_no AS VARCHAR) AS parentNo , COALESCE(S.order_no, 0) AS orderNo , CASE WHEN S.is_secret THEN 'Y' ELSE 'N' END AS secret , 'SERMONS' AS boardType , (SELECT COUNT(*) > 0 FROM com_file F WHERE F.pgm_id = 'sermon' AND F.ref_id = CAST(S.sermon_id AS VARCHAR) AND F.is_deleted = FALSE) AS hasFile , (SELECT COALESCE(SUM(F.file_size), 0) FROM com_file F WHERE F.pgm_id = 'sermon' AND F.ref_id = CAST(S.sermon_id AS VARCHAR) AND F.is_deleted = FALSE) AS totalFileSize , (SELECT COUNT(*) FROM com_comment C WHERE C.pgm_id = 'SERMONS' AND C.ref_id = CAST(S.sermon_id AS VARCHAR) AND C.is_deleted = FALSE) AS commentCount FROM official_sermon S WHERE S.is_deleted = FALSE
AND S.worship_type = #{worshipType}
AND S.title LIKE CONCAT('%', #{keyword}, '%')
AND S.content_text LIKE CONCAT('%', #{keyword}, '%')
AND S.author_id LIKE CONCAT('%', #{keyword}, '%')
AND S.worship_type = #{keyword}
AND (S.title LIKE CONCAT('%', #{keyword}, '%') OR S.content_text LIKE CONCAT('%', #{keyword}, '%'))
/* ===== ★ 동적 정렬 (ERP 수준) ===== - sortField가 전달되면 해당 필드로 정렬 - 그렇지 않으면 기본값(그룹순, 순서순)으로 정렬 - sortField는 Service에서 화이트리스트 검증 완료 (SQL Injection 안전) */
ORDER BY ${sortField} ${sortOrder}
ORDER BY S.group_no ASC, S.order_no ASC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE official_sermon
   SET title = #{title}
     , content_html = #{cont}
                 , content_text = REGEXP_REPLACE(COALESCE(#{cont}, ''), '<[^>]*>', '', 'g')
                 , preacher_name = #{preacherName}
                 , scripture_reference = #{scriptureReference}
                 , sermon_date = NULLIF(#{sermonDate}, '')::date
                 , worship_type = #{worshipType}
     , is_secret = CASE WHEN COALESCE(#{secret}, 'N') = 'Y' THEN TRUE ELSE FALSE END
     , password_hash = COALESCE(#{password}, password_hash)
     , updated_at = NOW()
     , updated_by = COALESCE(NULLIF(#{rqstId}, ''), updated_by)
 WHERE sermon_id = #{rqstNo}
   AND is_deleted = FALSE

UPDATE official_sermon
   SET order_no = order_no + 1
 WHERE group_no = #{groupNo}
   AND order_no >= #{orderNo}
   AND is_deleted = FALSE
